import React, { useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';

// --- Types ---
type HabitDefinition = string;

type DBEntry = {
  id: string;
  Task: string;
  Done: boolean;
  Type: 'Habit' | 'TODO';
  Date: string; // YYYY-MM-DD
};

// --- Mock Firebase / Persistence Layer ---
// In a real app, this would use the Firebase SDK (Firestore or Realtime DB).
// We use localStorage here to strictly adhere to the functional requirements without needing API keys.
const STORAGE_KEY_DB = 'app_db_table';
const STORAGE_KEY_DEFS = 'app_habit_definitions';

const DEFAULT_HABITS = [
  'Yoga',
  'Wasser trinken',
  'Zielerreichung prüfen',
  'Top 3 Aktivitäten eintragen',
];

const getTodayString = () => new Date().toISOString().split('T')[0];

const Persistence = {
  getDefinitions: (): string[] => {
    const stored = localStorage.getItem(STORAGE_KEY_DEFS);
    return stored ? JSON.parse(stored) : DEFAULT_HABITS;
  },

  saveDefinitions: (defs: string[]) => {
    localStorage.setItem(STORAGE_KEY_DEFS, JSON.stringify(defs));
  },

  getEntries: (): DBEntry[] => {
    const stored = localStorage.getItem(STORAGE_KEY_DB);
    return stored ? JSON.parse(stored) : [];
  },

  saveEntry: (entry: DBEntry) => {
    const entries = Persistence.getEntries();
    const index = entries.findIndex((e) => e.id === entry.id);
    if (index >= 0) {
      entries[index] = entry;
    } else {
      entries.push(entry);
    }
    localStorage.setItem(STORAGE_KEY_DB, JSON.stringify(entries));
    return entries;
  },

  // Syncs definitions to today's DB entries
  syncDailyHabits: (definitions: string[]) => {
    const today = getTodayString();
    let entries = Persistence.getEntries();
    let changed = false;

    // 1. Ensure all defined habits exist for today
    definitions.forEach((habitName) => {
      const exists = entries.find(
        (e) => e.Type === 'Habit' && e.Date === today && e.Task === habitName
      );
      if (!exists) {
        const newEntry: DBEntry = {
          id: crypto.randomUUID(),
          Task: habitName,
          Done: false,
          Type: 'Habit',
          Date: today,
        };
        entries.push(newEntry);
        changed = true;
      }
    });

    // 2. (Optional refinement) If a habit is DELETED from definitions, 
    // should we remove it from today's list? The prompt implies the Habits space
    // contains all entries from the dropdown list. So yes, we filter out 
    // habits that are no longer in definitions for *today*.
    const filteredEntries = entries.filter((e) => {
      if (e.Type === 'Habit' && e.Date === today) {
        return definitions.includes(e.Task);
      }
      return true;
    });

    if (filteredEntries.length !== entries.length) {
      entries = filteredEntries;
      changed = true;
    }

    if (changed) {
      localStorage.setItem(STORAGE_KEY_DB, JSON.stringify(entries));
    }
    return entries;
  },
};

// --- Components ---

const App = () => {
  // State
  const [definitions, setDefinitions] = useState<string[]>([]);
  const [entries, setEntries] = useState<DBEntry[]>([]);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [newHabitName, setNewHabitName] = useState('');

  // Load data on mount
  useEffect(() => {
    const defs = Persistence.getDefinitions();
    setDefinitions(defs);
    const updatedEntries = Persistence.syncDailyHabits(defs);
    setEntries(updatedEntries);
  }, []);

  // Filter entries for view
  const today = getTodayString();
  const todaysHabits = entries.filter(e => e.Type === 'Habit' && e.Date === today);
  const todaysTodos = entries.filter(e => e.Type === 'TODO' && e.Date === today);

  // Handlers
  const handleToggleDone = (entry: DBEntry) => {
    const updated = { ...entry, Done: !entry.Done };
    const newEntries = Persistence.saveEntry(updated);
    setEntries(newEntries);
  };

  const handleUpdateTask = (entry: DBEntry, newTask: string) => {
    const updated = { ...entry, Task: newTask };
    const newEntries = Persistence.saveEntry(updated);
    setEntries(newEntries);
  };

  const handleAddHabit = () => {
    if (!newHabitName.trim()) return;
    const newDefs = [...definitions, newHabitName.trim()];
    setDefinitions(newDefs);
    Persistence.saveDefinitions(newDefs);
    setEntries(Persistence.syncDailyHabits(newDefs));
    setNewHabitName('');
    setIsDropdownOpen(false);
  };

  const handleDeleteHabitDef = (e: React.MouseEvent, habitName: string) => {
    e.stopPropagation();
    const newDefs = definitions.filter(d => d !== habitName);
    setDefinitions(newDefs);
    Persistence.saveDefinitions(newDefs);
    setEntries(Persistence.syncDailyHabits(newDefs));
  };

  const handleAddTodo = () => {
    const newTodo: DBEntry = {
      id: crypto.randomUUID(),
      Task: '',
      Done: false,
      Type: 'TODO',
      Date: today,
    };
    const newEntries = Persistence.saveEntry(newTodo);
    setEntries(newEntries);
  };

  return (
    <div style={styles.container}>
      {/* --- Top Bar --- */}
      <div style={styles.topBar}>
        <div style={styles.controlGroup}>
          <label style={styles.label}>Habit List:</label>

          {/* Custom Dropdown */}
          <div style={styles.dropdownContainer}>
            <button 
              style={styles.dropdownButton} 
              onClick={() => setIsDropdownOpen(!isDropdownOpen)}
            >
              {definitions.length} Habits Configured ▼
            </button>

            {isDropdownOpen && (
              <div style={styles.dropdownMenu}>
                {definitions.length === 0 && <div style={styles.emptyItem}>No habits defined</div>}
                {definitions.map(habit => (
                  <div key={habit} style={styles.dropdownItem}>
                    <span style={styles.habitText}>{habit}</span>
                    <button 
                      style={styles.deleteBtn}
                      onClick={(e) => handleDeleteHabitDef(e, habit)}
                      title="Delete habit"
                    >
                      ×
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        <div style={styles.controlGroup}>
          <input
            style={styles.input}
            type="text"
            placeholder="New Habit Name"
            value={newHabitName}
            onChange={(e) => setNewHabitName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAddHabit()}
          />
          <button style={styles.primaryBtn} onClick={handleAddHabit}>
            Add habit
          </button>
        </div>
      </div>

      {/* --- Main Content --- */}
      <div style={styles.mainArea}>
        {/* Left: Habits */}
        <div style={styles.column}>
          <h2 style={styles.columnTitle}>Habits</h2>
          <div style={styles.list}>
            {todaysHabits.length === 0 && <div style={styles.emptyState}>No habits for today</div>}
            {todaysHabits.map(entry => (
              <div key={entry.id} style={styles.row}>
                <input
                  type="checkbox"
                  checked={entry.Done}
                  onChange={() => handleToggleDone(entry)}
                  style={styles.checkbox}
                />
                <span style={{
                  ...styles.taskText,
                  textDecoration: entry.Done ? 'line-through' : 'none',
                  color: entry.Done ? '#999' : '#333'
                }}>
                  {entry.Task}
                </span>
              </div>
            ))}
          </div>
        </div>

        {/* Right: TODOs */}
        <div style={styles.column}>
          <div style={styles.todoHeader}>
            <h2 style={styles.columnTitle}>TODOs</h2>
            <button style={styles.smallBtn} onClick={handleAddTodo}>+ New TODO</button>
          </div>
          <div style={styles.list}>
            {todaysTodos.length === 0 && <div style={styles.emptyState}>No TODOs yet</div>}
            {todaysTodos.map(entry => (
              <div key={entry.id} style={styles.row}>
                <input
                  type="checkbox"
                  checked={entry.Done}
                  onChange={() => handleToggleDone(entry)}
                  style={styles.checkbox}
                />
                <input
                  type="text"
                  value={entry.Task}
                  placeholder="Type task here..."
                  onChange={(e) => handleUpdateTask(entry, e.target.value)}
                  style={{
                    ...styles.editableInput,
                    textDecoration: entry.Done ? 'line-through' : 'none',
                    color: entry.Done ? '#999' : '#333'
                  }}
                />
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

// --- Styles ---
const styles: Record<string, React.CSSProperties> = {
  container: {
    fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif',
    maxWidth: '1200px',
    margin: '0 auto',
    height: '100vh',
    display: 'flex',
    flexDirection: 'column',
    backgroundColor: '#f9fafb',
  },
