// --- Initialize Firebase ---
const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

// Constants
const COLLECTION_ENTRIES = 'entries';
const COLLECTION_SETTINGS = 'settings';
const DOC_DEFINITIONS = 'habit_definitions';
const DEFAULT_HABITS = [
  'Yoga',
  'Wasser trinken',
  'Zielerreichung prüfen',
  'Top 3 Aktivitäten eintragen',
];

const getTodayString = () => new Date().toISOString().split('T')[0];

// --- Persistence Layer (Async) ---
const Persistence = {
  // Fetch the list of configured habits from Firestore
  getDefinitions: async (): Promise<string[]> => {
    try {
      const docRef = doc(db, COLLECTION_SETTINGS, DOC_DEFINITIONS);
      const snap = await getDoc(docRef);
      if (snap.exists()) {
        return snap.data().list || [];
      } else {
        // Initialize defaults if they don't exist
        await setDoc(docRef, { list: DEFAULT_HABITS });
        return DEFAULT_HABITS;
      }
    } catch (error) {
      console.error("Error fetching definitions:", error);
      return DEFAULT_HABITS;
    }
  },

  // Save the list of configured habits
  saveDefinitions: async (defs: string[]) => {
    try {
      await setDoc(doc(db, COLLECTION_SETTINGS, DOC_DEFINITIONS), { list: defs });
    } catch (error) {
      console.error("Error saving definitions:", error);
    }
  },

  // Get all TODOs and Habits for a specific date
  getEntriesForDate: async (dateStr: string): Promise<DBEntry[]> => {
    const q = query(collection(db, COLLECTION_ENTRIES), where("Date", "==", dateStr));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(d => ({ id: d.id, ...d.data() } as DBEntry));
  },

  // Update or Create a single entry
  saveEntry: async (entry: DBEntry) => {
    const { id, ...data } = entry;
    await setDoc(doc(db, COLLECTION_ENTRIES, id), data);
  },

  // Delete a single entry
  deleteEntry: async (id: string) => {
    await deleteDoc(doc(db, COLLECTION_ENTRIES, id));
  },

  // Ensure database has entries for habits on the specific date
  syncDailyHabits: async (definitions: string[], dateStr: string) => {
    // 1. Get existing habits for the specific date
    const q = query(
      collection(db, COLLECTION_ENTRIES), 
      where("Date", "==", dateStr),
      where("Type", "==", "Habit")
    );
    const snap = await getDocs(q);
    const existingTasks = snap.docs.map(d => d.data().Task);

    // 2. Create missing entries
    const promises = [];
    for (const habitName of definitions) {
      if (!existingTasks.includes(habitName)) {
        const newDocRef = doc(collection(db, COLLECTION_ENTRIES));
        const newEntry = {
          Task: habitName,
          Done: false,
          Type: 'Habit',
          Date: dateStr,
        };
        promises.push(setDoc(newDocRef, newEntry));
      }
    }

    await Promise.all(promises);
  },
};

// --- Components ---

const App = () => {
  // State
  const [loading, setLoading] = useState(true);
  const [selectedDate, setSelectedDate] = useState(getTodayString());
  const [definitions, setDefinitions] = useState<string[]>([]);
  const [entries, setEntries] = useState<DBEntry[]>([]);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [newHabitName, setNewHabitName] = useState('');

  // Load data whenever selectedDate changes
  useEffect(() => {
    const initData = async () => {
      setLoading(true);
      // 1. Get Definitions (always fetch fresh to be safe)
      const defs = await Persistence.getDefinitions();
      setDefinitions(defs);

      // 2. Sync DB (create habits if missing for the selected date)
      await Persistence.syncDailyHabits(defs, selectedDate);

      // 3. Fetch all of the selected date's entries
      const dateEntries = await Persistence.getEntriesForDate(selectedDate);
      setEntries(dateEntries);
      setLoading(false);
    };

    initData();
  }, [selectedDate]);

  // Filter entries for view
  // CHANGED: We removed "&& definitions.includes(e.Task)" so that existing DB entries
  // are shown even if they are removed from the dropdown list.
  const dailyHabits = entries.filter(e => 
    e.Type === 'Habit' && e.Date === selectedDate
  );
  const dailyTodos = entries.filter(e => e.Type === 'TODO' && e.Date === selectedDate);

  // Handlers

  const handleDateOffset = (offset: number) => {
    const date = new Date(selectedDate);
    date.setDate(date.getDate() + offset);
    setSelectedDate(date.toISOString().split('T')[0]);
  };

  const handleToggleDone = async (entry: DBEntry) => {
    // Optimistic Update
    const updatedEntry = { ...entry, Done: !entry.Done };
    setEntries(prev => prev.map(e => e.id === entry.id ? updatedEntry : e));

    // DB Update
    await Persistence.saveEntry(updatedEntry);
  };

  const handleUpdateTask = async (entry: DBEntry, newTask: string) => {
    // Optimistic Update
    const updatedEntry = { ...entry, Task: newTask };
    setEntries(prev => prev.map(e => e.id === entry.id ? updatedEntry : e));

    // DB Update
    await Persistence.saveEntry(updatedEntry);
  };

  const handleDeleteEntry = async (entry: DBEntry) => {
    if (!confirm('Are you sure you want to delete this entry?')) return;

    // Optimistic Update
    setEntries(prev => prev.filter(e => e.id !== entry.id));

    // DB Update
    await Persistence.deleteEntry(entry.id);
  };

  const handleAddHabit = async () => {
    if (!newHabitName.trim()) return;
    const name = newHabitName.trim();
    if (definitions.includes(name)) return; // Prevent duplicates

    const newDefs = [...definitions, name];
    setDefinitions(newDefs);
    setNewHabitName('');
    setIsDropdownOpen(false);

    // Async operations
    await Persistence.saveDefinitions(newDefs);
    await Persistence.syncDailyHabits(newDefs, selectedDate);
    const freshEntries = await Persistence.getEntriesForDate(selectedDate);
    setEntries(freshEntries);
  };

  const handleDeleteHabitDef = async (e: React.MouseEvent, habitName: string) => {
    e.stopPropagation();
    const newDefs = definitions.filter(d => d !== habitName);
    setDefinitions(newDefs);

    // Only update the definitions list, do not touch existing entries
    await Persistence.saveDefinitions(newDefs);
  };

  const handleAddTodo = async () => {
    const newDocRef = doc(collection(db, COLLECTION_ENTRIES));
    const newTodo: DBEntry = {
      id: newDocRef.id,
      Task: '',
      Done: false,
      Type: 'TODO',
      Date: selectedDate,
    };

    // Optimistic Update
    setEntries(prev => [...prev, newTodo]);

    // DB Update
    await setDoc(newDocRef, {
        Task: newTodo.Task,
        Done: newTodo.Done,
        Type: newTodo.Type,
        Date: newTodo.Date
    });
  };

  if (loading) {
    return (
      <div style={{ ...styles.container, justifyContent: 'center', alignItems: 'center' }}>
        <div style={{ fontSize: '1.2rem', color: '#666' }}>Loading data...</div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      {/* --- Top Bar --- */}
      <div style={styles.topBar}>
        <div style={styles.controlGroup}>
          <label style={styles.label}>Habit List:</label>

          {/* Custom Dropdown */}
          <div style={styles.dropdownContainer}>
            <button 
              style={styles.dropdownButton} 
              onClick={() => setIsDropdownOpen(!isDropdownOpen)}
            >
              {definitions.length} Habits Configured ▼
            </button>

            {isDropdownOpen && (
              <div style={styles.dropdownMenu}>
                {definitions.length === 0 && <div style={styles.emptyItem}>No habits defined</div>}
                {definitions.map(habit => (
                  <div key={habit} style={styles.dropdownItem}>
                    <span style={styles.habitText}>{habit}</span>
                    <button 
                      style={styles.deleteBtn}
                      onClick={(e) => handleDeleteHabitDef(e, habit)}
                      title="Delete habit definition"
                    >
                      ×
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        <div style={styles.controlGroup}>
          <input
            style={styles.input}
            type="text"
            placeholder="New Habit Name"
            value={newHabitName}
            onChange={(e) => setNewHabitName(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleAddHabit()}
          />
          <button style={styles.primaryBtn} onClick={handleAddHabit}>
            Add habit
          </button>
        </div>

        {/* Date Picker with Nav Buttons */}
        <div style={styles.controlGroup}>
          <label style={styles.label}>Date:</label>
          <div style={{ display: 'flex', gap: '5px' }}>
            <button onClick={() => handleDateOffset(-1)} style={styles.navBtn}>&lt;</button>
            <input 
              type="date" 
              style={styles.dateInput}
              value={selectedDate}
              onChange={(e) => setSelectedDate(e.target.value)}
            />
            <button onClick={() => handleDateOffset(1)} style={styles.navBtn}>&gt;</button>
          </div>
        </div>
      </div>

      {/* --- Main Content --- */}
      <div style={styles.mainArea}>
        {/* Left: Habits */}
        <div style={styles.column}>
          <h2 style={styles.columnTitle}>Habits ({selectedDate})</h2>
          <div style={styles.list}>
            {dailyHabits.length === 0 && <div style={styles.emptyState}>No habits found</div>}
            {dailyHabits.map(entry => (
              <div key={entry.id} style={styles.row}>
                <input
                  type="checkbox"
                  checked={entry.Done}
                  onChange={() => handleToggleDone(entry)}
                  style={styles.checkbox}
                />
                <span style={{
                  ...styles.taskText,
                  textDecoration: entry.Done ? 'line-through' : 'none',
                  color: entry.Done ? '#999' : '#333'
                }}>
                  {entry.Task}
                </span>
                <button 
                  style={styles.rowDeleteBtn} 
                  onClick={() => handleDeleteEntry(entry)}
                  title="Delete entry"
                >
                  ×
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Right: TODOs */}
        <div style={styles.column}>
          <div style={styles.todoHeader}>
            <h2 style={styles.columnTitle}>TODOs</h2>
            <button style={styles.smallBtn} onClick={handleAddTodo}>+ New TODO</button>
          </div>
          <div style={styles.list}>
            {dailyTodos.length === 0 && <div style={styles.emptyState}>No TODOs for this date</div>}
            {dailyTodos.map(entry => (
              <div key={entry.id} style={styles.row}>
                <input
                  type="checkbox"
                  checked={entry.Done}
                  onChange={() => handleToggleDone(entry)}
                  style={styles.checkbox}
                />
                <input
                  type="text"
                  value={entry.Task}
                  placeholder="Type task here..."
                  onChange={(e) => handleUpdateTask(entry, e.target.value)}
                  style={{
                    ...styles.editableInput,
                    textDecoration: entry.Done ? 'line-through' : 'none',
                    color: entry.Done ? '#999' : '#333'
                  }}
                />
                <button 
                  style={styles.rowDeleteBtn} 
                  onClick={() => handleDeleteEntry(entry)}
                  title="Delete entry"
                >
                  ×
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

